// // This module implements a 2-to-1 multiplexer where the output is selected from a or b based on the value of sel_b1. If sel_b1 is false, the output will be b; otherwise, it will be a.
module mux_2to1(
    input a,
    input b,
    input sel_b1,
    output reg out_mux
);

always @(*) begin
    if(sel_b1) begin
        out_mux = b;
    end else begin
        out_mux = a;
    end
end

endmodule
